import java.io.IOException;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        String responseHtml = "<html><body>User Input: " + sanitizedInput + "</body></html>";
        response.setContentType("text/html");
        response.getWriter().write(responseHtml);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization and escaping logic here
        // Example: Using OWASP Java HTML Sanitizer Library
        return org.owasp.html.PolicyFactory.sanitize(input);
    }
}

